// The synthetic det-fn ensures has the shape
//     ({ A_post1 && A_post2 }) ==> det_map_4k_page_equal(r1, r2, post1_self_, post2_self_)
// where  det_map_4k_page_equal == (r1 == r2) && (post1_self_.view() == post2_self_.view()).
//
// `PageTable::view()` is a `closed spec fn` returning a `PageTableView` whose 14
// fields include several that the ensures of `map_4k_page` does NOT pin between
// the two runs (cr3, pcid, ioid, l3_rev_map, l2_rev_map, l1_rev_map,
// tlb_mapping_4k/2m/1g).  The previous attempt tried to lift the per-field
// equalities of the *pinned* observables to a full `post1_self_@ =~=
// post2_self_@`, which failed: there is no hypothesis pinning the unpinned view
// fields.
//
// To give z3 every available equality without making any unsound claim, we
// open the implication branch and re-state each ensures conjunct on both runs
// so that the triggers are primed and z3 sees the per-field chains
// (post1 == pre == post2) for the observables the ensures *does* pin.  We do
// NOT assert the unprovable view equality.

if ({
    &&& (post1_self_.wf())
    &&& (post1_self_.kernel_l4_end == pre_self_.kernel_l4_end)
    &&& (post1_self_.page_closure() =~= pre_self_.page_closure())
    &&& (post1_self_.mapping_4k@ == pre_self_.mapping_4k@.insert(
            spec_index2va((target_l4i, target_l3i, target_l2i, target_l1i)),
            *target_entry,
        ))
    &&& (post1_self_.mapping_2m() =~= pre_self_.mapping_2m())
    &&& (post1_self_.mapping_1g() =~= pre_self_.mapping_1g())
    &&& (post1_self_.kernel_entries =~= pre_self_.kernel_entries)
    &&& (post2_self_.wf())
    &&& (post2_self_.kernel_l4_end == pre_self_.kernel_l4_end)
    &&& (post2_self_.page_closure() =~= pre_self_.page_closure())
    &&& (post2_self_.mapping_4k@ == pre_self_.mapping_4k@.insert(
            spec_index2va((target_l4i, target_l3i, target_l2i, target_l1i)),
            *target_entry,
        ))
    &&& (post2_self_.mapping_2m() =~= pre_self_.mapping_2m())
    &&& (post2_self_.mapping_1g() =~= pre_self_.mapping_1g())
    &&& (post2_self_.kernel_entries =~= pre_self_.kernel_entries)
}) {
    // r1, r2 are both unit `()`, so trivially equal.
    assert(r1 == r2);

    // kernel_l4_end: both runs pinned to pre_self_.kernel_l4_end.
    assert(post1_self_.kernel_l4_end == pre_self_.kernel_l4_end);
    assert(post2_self_.kernel_l4_end == pre_self_.kernel_l4_end);
    assert(post1_self_.kernel_l4_end == post2_self_.kernel_l4_end);

    // page_closure(): both runs pinned (extensional) to pre_self_.page_closure().
    assert(post1_self_.page_closure() =~= pre_self_.page_closure());
    assert(post2_self_.page_closure() =~= pre_self_.page_closure());
    assert(post1_self_.page_closure() =~= post2_self_.page_closure());
    assert(post1_self_.page_closure() == post2_self_.page_closure());

    // mapping_4k@: both runs pinned to pre_self_.mapping_4k@.insert(va, *target_entry).
    assert(post1_self_.mapping_4k@ == pre_self_.mapping_4k@.insert(
        spec_index2va((target_l4i, target_l3i, target_l2i, target_l1i)),
        *target_entry,
    ));
    assert(post2_self_.mapping_4k@ == pre_self_.mapping_4k@.insert(
        spec_index2va((target_l4i, target_l3i, target_l2i, target_l1i)),
        *target_entry,
    ));
    assert(post1_self_.mapping_4k@ =~= post2_self_.mapping_4k@);
    assert(post1_self_.mapping_4k@ == post2_self_.mapping_4k@);

    // mapping_2m(): both runs pinned (extensional) to pre_self_.mapping_2m().
    assert(post1_self_.mapping_2m() =~= pre_self_.mapping_2m());
    assert(post2_self_.mapping_2m() =~= pre_self_.mapping_2m());
    assert(post1_self_.mapping_2m() =~= post2_self_.mapping_2m());
    assert(post1_self_.mapping_2m@ =~= post2_self_.mapping_2m@);
    assert(post1_self_.mapping_2m@ == post2_self_.mapping_2m@);

    // mapping_1g(): both runs pinned (extensional) to pre_self_.mapping_1g().
    assert(post1_self_.mapping_1g() =~= pre_self_.mapping_1g());
    assert(post2_self_.mapping_1g() =~= pre_self_.mapping_1g());
    assert(post1_self_.mapping_1g() =~= post2_self_.mapping_1g());
    assert(post1_self_.mapping_1g@ =~= post2_self_.mapping_1g@);
    assert(post1_self_.mapping_1g@ == post2_self_.mapping_1g@);

    // kernel_entries: both runs pinned (extensional) to pre_self_.kernel_entries.
    assert(post1_self_.kernel_entries =~= pre_self_.kernel_entries);
    assert(post2_self_.kernel_entries =~= pre_self_.kernel_entries);
    assert(post1_self_.kernel_entries =~= post2_self_.kernel_entries);
    assert(post1_self_.kernel_entries == post2_self_.kernel_entries);
    assert(post1_self_.kernel_entries@ =~= post2_self_.kernel_entries@);
    assert(post1_self_.kernel_entries@ == post2_self_.kernel_entries@);

    // wf() on both runs (kept for trigger priming).
    assert(post1_self_.wf());
    assert(post2_self_.wf());
}
